const isDark = context.grafana.theme.isDark;
const gc = isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)';
const tc = isDark ? '#9E9E9E' : '#777';

const frame = context.panel.data.series[0];
if (!frame || !frame.fields || frame.fields.length === 0) return {};

const tf  = frame.fields.find(f => f.name === 'Time' || f.name === 'time');
const pf  = frame.fields.find(f => f.name === 'price');
const sf  = frame.fields.find(f => f.name === 'sell_ratio');
const of_ = frame.fields.find(f => f.name === 'oi_norm');
if (!tf || !pf) return {};

const n      = tf.values.length;
const times  = tf.values;
const prices = pf.values;
const sell   = sf  ? sf.values  : new Array(n).fill(null);
const oi     = of_ ? of_.values : new Array(n).fill(null);

const VAH = 2.90, POC = 2.45;
const SHORT_SELL = 72, SHORT_OI = 74;
const LONG_SELL  = 63, LONG_OI  = 58;

const labels = times.map(t => {
  const d = new Date(typeof t === 'number' ? t : Number(t));
  return (d.getMonth()+1)+'/'+(d.getDate())+' '+String(d.getHours()).padStart(2,'0')+'h';
});

const markAreas  = [];
const markPoints = [];

for (let i = 0; i < n; i++) {
  const p  = typeof prices[i] === 'number' ? prices[i] : null;
  const s  = typeof sell[i]   === 'number' ? sell[i]   : 0;
  const o2 = typeof oi[i]     === 'number' ? oi[i]     : 0;
  if (p === null) continue;
  const x1 = labels[i];
  const x2 = labels[Math.min(i + 1, n - 1)];
  const isShort = p > VAH && s > SHORT_SELL && o2 > SHORT_OI;
  const isLong  = p < POC && s < LONG_SELL  && o2 < LONG_OI;
  if (isShort) {
    markAreas.push([{ xAxis: x1, itemStyle: { color: 'rgba(226,75,74,0.15)' } }, { xAxis: x2 }]);
    markPoints.push({ coord: [x1, p], symbol: 'triangle', symbolSize: 12, symbolRotate: 180, itemStyle: { color: '#E24B4A' }, label: { show: true, formatter: '▼S', fontSize: 9, color: '#fff', position: 'inside' } });
  }
  if (isLong) {
    markAreas.push([{ xAxis: x1, itemStyle: { color: 'rgba(99,153,34,0.15)' } }, { xAxis: x2 }]);
    markPoints.push({ coord: [x1, p], symbol: 'triangle', symbolSize: 12, symbolRotate: 0, itemStyle: { color: '#639922' }, label: { show: true, formatter: '▲L', fontSize: 9, color: '#fff', position: 'inside' } });
  }
}

const priceData = prices.map(v => typeof v === 'number' ? v : null);
const interval  = Math.max(1, Math.floor(n / 8));

return {
  tooltip: {
    trigger: 'axis',
    formatter: function(params) {
      const p = Array.isArray(params) ? params[0] : params;
      const val = p && typeof p.value === 'number' ? '$' + p.value.toFixed(4) : '-';
      return (p ? p.axisValue : '') + '<br>' + val;
    }
  },
  grid: { left: 65, right: 20, top: 20, bottom: 36 },
  xAxis: {
    type: 'category', data: labels,
    axisLabel: { fontSize: 10, color: tc, rotate: 20, interval: interval },
    axisLine: { lineStyle: { color: gc } }
  },
  yAxis: {
    type: 'value', scale: true,
    axisLabel: { formatter: function(v) { return '$' + (v || 0).toFixed(2); }, fontSize: 10, color: tc },
    splitLine: { lineStyle: { color: gc } }
  },
  series: [{
    name: 'ICP/USDT',
    type: 'line',
    data: priceData,
    lineStyle: { color: '#888780', width: 2 },
    areaStyle: { color: 'rgba(136,135,128,0.07)' },
    smooth: false,
    symbol: 'none',
    connectNulls: false,
    markLine: {
      silent: true,
      symbol: 'none',
      data: [
        { yAxis: VAH, lineStyle: { color: 'rgba(226,75,74,0.65)', type: 'dashed', width: 1.5 }, label: { formatter: 'VAH $' + VAH, position: 'insideStartTop',    fontSize: 10, color: 'rgba(226,75,74,0.9)' } },
        { yAxis: POC, lineStyle: { color: 'rgba(99,153,34,0.65)',  type: 'dashed', width: 1.5 }, label: { formatter: 'POC $' + POC, position: 'insideStartBottom', fontSize: 10, color: 'rgba(99,153,34,0.9)'  } }
      ]
    },
    markArea:  { silent: true, data: markAreas },
    markPoint: { data: markPoints }
  }]
};

const isDark = context.grafana.theme.isDark;
const gc = isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)';
const tc = isDark ? '#9E9E9E' : '#777';

const frame = context.panel.data.series[0];
if (!frame || !frame.fields || frame.fields.length === 0) return {};

const tf  = frame.fields.find(f => f.name === 'Time' || f.name === 'time');
const sf  = frame.fields.find(f => f.name === 'sell_ratio');
const of_ = frame.fields.find(f => f.name === 'oi_norm');
if (!tf || !sf) return {};

const n     = tf.values.length;
const times = tf.values;
const sell  = sf.values.map(v  => typeof v  === 'number' ? v  : null);
const oi    = of_ ? of_.values.map(v => typeof v === 'number' ? v : null) : new Array(n).fill(null);

const SHORT_SELL = 72, LONG_SELL = 63;

const labels = times.map(t => {
  const d = new Date(typeof t === 'number' ? t : Number(t));
  return (d.getMonth()+1)+'/'+(d.getDate())+' '+String(d.getHours()).padStart(2,'0')+'h';
});

const markAreas = [];
for (let i = 0; i < n; i++) {
  const s  = typeof sell[i] === 'number' ? sell[i] : null;
  if (s === null) continue;
  const x1 = labels[i], x2 = labels[Math.min(i+1, n-1)];
  if (s > SHORT_SELL) markAreas.push([{ xAxis: x1, itemStyle: { color: 'rgba(226,75,74,0.10)' } }, { xAxis: x2 }]);
  if (s < LONG_SELL)  markAreas.push([{ xAxis: x1, itemStyle: { color: 'rgba(99,153,34,0.10)'  } }, { xAxis: x2 }]);
}

const interval = Math.max(1, Math.floor(n / 8));

const series = [
  {
    name: 'Sell-Pressure-Ratio',
    type: 'line',
    data: sell,
    lineStyle: { color: '#D85A30', width: 2 },
    areaStyle: { color: 'rgba(216,90,48,0.07)' },
    smooth: false,
    symbol: 'none',
    connectNulls: false,
    markLine: {
      silent: true, symbol: 'none',
      data: [
        { yAxis: SHORT_SELL, lineStyle: { color: 'rgba(226,75,74,0.5)', type: 'dotted', width: 1 }, label: { formatter: 'SHORT >' + SHORT_SELL + '%', position: 'insideStartTop',    fontSize: 9, color: 'rgba(226,75,74,0.8)' } },
        { yAxis: LONG_SELL,  lineStyle: { color: 'rgba(99,153,34,0.5)',  type: 'dotted', width: 1 }, label: { formatter: 'LONG <'  + LONG_SELL  + '%', position: 'insideStartBottom', fontSize: 9, color: 'rgba(99,153,34,0.8)'  } }
      ]
    },
    markArea: { silent: true, data: markAreas }
  }
];

if (oi.some(v => v !== null)) {
  series.push({
    name: 'Long OI (norm.)',
    type: 'line',
    data: oi,
    lineStyle: { color: '#185FA5', width: 1.5, type: 'dashed' },
    smooth: false,
    symbol: 'none',
    connectNulls: false
  });
}

return {
  tooltip: {
    trigger: 'axis',
    formatter: function(params) {
      if (!Array.isArray(params)) return '';
      return params[0].axisValue + '<br>' + params.map(function(p) {
        const val = typeof p.value === 'number' ? p.value.toFixed(1) + '%' : '-';
        return p.seriesName + ': ' + val;
      }).join('<br>');
    }
  },
  legend: { data: ['Sell-Pressure-Ratio', 'Long OI (norm.)'], textStyle: { color: tc, fontSize: 11 }, top: 4 },
  grid: { left: 55, right: 20, top: 32, bottom: 36 },
  xAxis: {
    type: 'category', data: labels,
    axisLabel: { fontSize: 10, color: tc, rotate: 20, interval: interval },
    axisLine: { lineStyle: { color: gc } }
  },
  yAxis: {
    type: 'value', min: 30, max: 105,
    axisLabel: { formatter: function(v) { return v + '%'; }, fontSize: 10, color: tc },
    splitLine: { lineStyle: { color: gc } }
  },
  series: series
};
